#!/usr/bin/env node
// jsonplaceholder-cli — Generated by clify. Edit at your own risk; `clify sync` overwrites.
import { parseArgs } from "node:util";
import { readFileSync, existsSync, statSync, createReadStream } from "node:fs";
import { resolve, dirname, join } from "node:path";
import { fileURLToPath } from "node:url";

const __dirname = dirname(fileURLToPath(import.meta.url));
const REPO_ROOT = resolve(__dirname, "..");

const pkg = JSON.parse(readFileSync(join(REPO_ROOT, "package.json"), "utf8"));
const VERSION = pkg.version;

// ---------- env loader ----------
function loadEnv() {
  const path = join(REPO_ROOT, ".env");
  if (!existsSync(path)) return;
  for (const line of readFileSync(path, "utf8").split("\n")) {
    const trimmed = line.trim();
    if (!trimmed || trimmed.startsWith("#")) continue;
    const eq = trimmed.indexOf("=");
    if (eq === -1) continue;
    const key = trimmed.slice(0, eq).trim();
    let val = trimmed.slice(eq + 1).trim();
    if ((val.startsWith('"') && val.endsWith('"')) || (val.startsWith("'") && val.endsWith("'"))) {
      val = val.slice(1, -1);
    }
    if (process.env[key] === undefined) process.env[key] = val;
  }
}
loadEnv();

const BASE_URL = (process.env.JSONPLACEHOLDER_BASE_URL || "https://jsonplaceholder.typicode.com").replace(/\/$/, "");

// ---------- resource registry ----------
function crudResource(name, idField = "id") {
  return {
    list:   { method: "GET",    path: `/${name}`,                _flags: {} },
    get:    { method: "GET",    path: `/${name}/:id`,            _flags: { id: { type: "string", required: true, description: `${name.slice(0,-1)} id` } } },
    create: { method: "POST",   path: `/${name}`,                _flags: bodyFlagsFor(name) },
    update: { method: "PUT",    path: `/${name}/:id`,            _flags: { id: { type: "string", required: true, description: `${name.slice(0,-1)} id` }, ...bodyFlagsFor(name) } },
    delete: { method: "DELETE", path: `/${name}/:id`,            _flags: { id: { type: "string", required: true, description: `${name.slice(0,-1)} id` } } },
  };
}

function bodyFlagsFor(resource) {
  const common = { body: { type: "string", required: false, description: "Raw JSON body (overrides individual flags)" } };
  switch (resource) {
    case "posts":    return { ...common, title:  { type: "string", description: "Post title" },  body_text: { type: "string", description: "Post body (mapped to 'body')" }, userId: { type: "string", description: "Author user id" } };
    case "comments": return { ...common, name:   { type: "string", description: "Commenter name" }, email: { type: "string", description: "Commenter email" }, body_text: { type: "string", description: "Comment body (mapped to 'body')" }, postId: { type: "string", description: "Parent post id" } };
    case "albums":   return { ...common, title:  { type: "string", description: "Album title" },    userId: { type: "string", description: "Owner user id" } };
    case "photos":   return { ...common, title:  { type: "string", description: "Photo title" },    url: { type: "string", description: "Photo URL" }, thumbnailUrl: { type: "string", description: "Thumbnail URL" }, albumId: { type: "string", description: "Parent album id" } };
    case "todos":    return { ...common, title:  { type: "string", description: "Todo title" },     completed: { type: "boolean", description: "Completed flag" }, userId: { type: "string", description: "Owner user id" } };
    case "users":    return { ...common, name:   { type: "string", description: "User name" },      username: { type: "string", description: "Username" }, email: { type: "string", description: "Email" } };
    default:         return common;
  }
}

// translate body_text → body in payloads (avoid clashing with --body raw escape hatch)
function buildPayload(resource, values) {
  const out = {};
  for (const [k, v] of Object.entries(values)) {
    if (v === undefined) continue;
    if (k === "body") continue;
    if (k === "id") continue;
    if (k === "body_text") out.body = v;
    else if (k === "userId" || k === "postId" || k === "albumId") out[k] = Number(v);
    else out[k] = v;
  }
  return out;
}

const RESOURCES = {
  posts:    crudResource("posts"),
  comments: crudResource("comments"),
  albums:   crudResource("albums"),
  photos:   crudResource("photos"),
  todos:    crudResource("todos"),
  users:    crudResource("users"),
};

// ---------- arg parsing ----------
// --help/-h stay in `rest` so each layer can decide which help to show.
const GLOBAL_FLAGS = new Set(["--json", "--dry-run", "--version", "-v", "--verbose", "--all"]);

function splitGlobal(argv) {
  const global = {};
  const rest = [];
  for (const arg of argv) {
    if (GLOBAL_FLAGS.has(arg)) {
      const key = arg.replace(/^--?/, "").replace(/-/g, "_");
      global[key] = true;
      if (arg === "-v") global.version = true;
      if (arg === "--dry-run") global.dry_run = true;
    } else {
      rest.push(arg);
    }
  }
  return { global, rest };
}

function hasHelp(args) {
  return args.includes("--help") || args.includes("-h");
}

function toParseArgs(flagSpec) {
  const options = {};
  for (const [name, spec] of Object.entries(flagSpec)) {
    options[name] = { type: spec.type === "boolean" ? "boolean" : "string" };
  }
  return options;
}

function checkRequired(values, flagSpec) {
  const missing = [];
  for (const [name, spec] of Object.entries(flagSpec)) {
    if (spec.required && (values[name] === undefined || values[name] === "")) missing.push(name);
  }
  return missing;
}

// ---------- output ----------
const isPiped = !process.stdout.isTTY;

function output(data, jsonRequested) {
  const wantJson = jsonRequested || isPiped;
  if (wantJson) {
    process.stdout.write(JSON.stringify(data, null, 2) + "\n");
  } else if (data === null || data === undefined) {
    process.stdout.write("\n");
  } else if (typeof data === "string") {
    process.stdout.write(data + "\n");
  } else if (Array.isArray(data)) {
    process.stdout.write(JSON.stringify(data, null, 2) + "\n");
  } else {
    process.stdout.write(JSON.stringify(data, null, 2) + "\n");
  }
}

function errorOut(code, message, opts = {}) {
  const obj = { type: "error", code, message, retryable: !!opts.retryable };
  if (opts.retryAfter !== undefined) obj.retryAfter = opts.retryAfter;
  if (opts.details) obj.details = opts.details;
  if (process.env.__JSONPLACEHOLDER_FORCE_JSON_ERR === "1" || isPiped) {
    process.stderr.write(JSON.stringify(obj) + "\n");
  } else {
    process.stderr.write(`error[${code}]: ${message}\n`);
  }
  process.exit(1);
}

// ---------- HTTP ----------
async function apiRequest({ method, path, query, body, headers = {}, dryRun, verbose, idempotencyKey, ifMatch, file }) {
  const url = new URL(BASE_URL + path);
  if (query) {
    for (const [k, v] of Object.entries(query)) {
      if (v !== undefined) url.searchParams.set(k, String(v));
    }
  }

  const reqHeaders = { "user-agent": `jsonplaceholder-cli/${VERSION}`, ...headers };
  let reqBody;

  if (file) {
    if (!existsSync(file)) errorOut("validation_error", `File not found: ${file}`);
    const fd = new FormData();
    const buf = readFileSync(file);
    const blob = new Blob([buf]);
    fd.append("file", blob, file.split("/").pop());
    reqBody = fd;
  } else if (body !== undefined && method !== "GET" && method !== "DELETE") {
    reqHeaders["content-type"] = "application/json";
    reqBody = JSON.stringify(body);
  }

  if (idempotencyKey) reqHeaders["idempotency-key"] = idempotencyKey;
  if (ifMatch) reqHeaders["if-match"] = ifMatch;

  if (dryRun) {
    return { __dryRun: true, method, url: url.toString(), headers: reqHeaders, body: body ?? null };
  }

  let res;
  try {
    res = await fetch(url, { method, headers: reqHeaders, body: reqBody });
  } catch (err) {
    if (err.name === "AbortError" || /timeout/i.test(err.message || "")) {
      errorOut("timeout", `Request timed out: ${err.message}`, { retryable: true });
    }
    errorOut("network_error", `Network error: ${err.message}`, { retryable: true });
  }

  const status = res.status;
  const retryAfterHeader = res.headers.get("retry-after");
  const retryAfter = retryAfterHeader ? Number(retryAfterHeader) : undefined;

  let parsed;
  const text = await res.text();
  try { parsed = text ? JSON.parse(text) : null; } catch { parsed = text; }

  if (verbose) {
    const headerObj = {};
    res.headers.forEach((v, k) => { headerObj[k] = v; });
    process.stderr.write(JSON.stringify({ status, headers: headerObj }) + "\n");
  }

  if (status >= 200 && status < 300) return parsed;

  // error mapping
  const baseMsg = parsed && typeof parsed === "object" && parsed.message ? parsed.message : `HTTP ${status}`;
  if (status === 401) errorOut("auth_invalid", baseMsg);
  if (status === 403) errorOut("forbidden", baseMsg);
  if (status === 404) errorOut("not_found", baseMsg);
  if (status === 409) errorOut("conflict", baseMsg);
  if (status === 400 || status === 422) errorOut("validation_error", baseMsg, { details: parsed });
  if (status === 429) errorOut("rate_limited", `Rate limited.${retryAfter ? ` Retry after ${retryAfter}s.` : ""}`, { retryable: true, retryAfter });
  if (status >= 500) errorOut("server_error", baseMsg, { retryable: true, retryAfter });
  errorOut("network_error", baseMsg);
}

// ---------- help ----------
function showRootHelp() {
  let out = `jsonplaceholder-cli ${VERSION}\nCLI for the JSONPlaceholder API.\n\nUsage:\n  jsonplaceholder-cli <resource> <action> [flags]\n\nGlobal flags:\n  --json           Force JSON output\n  --dry-run        Print request without sending\n  --verbose        Print response status & headers to stderr\n  --all            Auto-paginate (no-op for JSONPlaceholder)\n  --version, -v    Print version\n  --help, -h       Show this help\n\nResources:\n`;
  for (const r of Object.keys(RESOURCES).sort()) {
    out += `  ${r.padEnd(10)} ${Object.keys(RESOURCES[r]).join(", ")}\n`;
  }
  out += `\nUse 'jsonplaceholder-cli <resource> --help' for actions, or '<resource> <action> --help' for flags.\n`;
  return out;
}

function showResourceHelp(resource) {
  const actions = RESOURCES[resource];
  let out = `jsonplaceholder-cli ${resource}\n\nActions:\n`;
  for (const [name, def] of Object.entries(actions)) {
    out += `  ${name.padEnd(10)} ${def.method} ${def.path}\n`;
  }
  out += `\nUse 'jsonplaceholder-cli ${resource} <action> --help' for flags.\n`;
  return out;
}

function showActionHelp(resource, action) {
  const def = RESOURCES[resource][action];
  let out = `jsonplaceholder-cli ${resource} ${action}\n\n${def.method} ${def.path}\n\nFlags:\n`;
  const entries = Object.entries(def._flags);
  if (entries.length === 0) out += `  (none)\n`;
  for (const [name, spec] of entries) {
    const req = spec.required ? "required" : "optional";
    const desc = spec.description || "";
    out += `  --${name.padEnd(20)} ${spec.type.padEnd(8)} ${req.padEnd(8)} ${desc}\n`;
  }
  return out;
}

// ---------- main ----------
async function main() {
  const argv = process.argv.slice(2);
  const { global, rest } = splitGlobal(argv);

  if (global.version) { process.stdout.write(VERSION + "\n"); return; }

  // No positional args, or only --help/-h → root help
  const positional = rest.filter((a) => a !== "--help" && a !== "-h");
  if (positional.length === 0) { process.stdout.write(showRootHelp()); return; }

  const [resourceArg, actionArg, ...remaining] = positional;

  if (!RESOURCES[resourceArg]) {
    const available = Object.keys(RESOURCES).join(", ");
    errorOut("validation_error", `Unknown resource: ${resourceArg}. Available: ${available}`);
  }

  // <resource> --help (no action provided)
  if (!actionArg) {
    process.stdout.write(showResourceHelp(resourceArg));
    return;
  }

  const def = RESOURCES[resourceArg][actionArg];
  if (!def) {
    const available = Object.keys(RESOURCES[resourceArg]).join(", ");
    errorOut("validation_error", `Unknown action: ${actionArg} on ${resourceArg}. Available: ${available}`);
  }

  // <resource> <action> --help → action help
  if (hasHelp(rest)) {
    process.stdout.write(showActionHelp(resourceArg, actionArg));
    return;
  }

  let parsed;
  try {
    parsed = parseArgs({ args: remaining, options: toParseArgs(def._flags), strict: true, allowPositionals: false });
  } catch (err) {
    errorOut("validation_error", err.message);
  }

  const missing = checkRequired(parsed.values, def._flags);
  if (missing.length) errorOut("validation_error", `Missing required flag(s): ${missing.map((m) => `--${m}`).join(", ")}`);

  // path interpolation
  let path = def.path;
  for (const m of path.matchAll(/:([a-zA-Z]+)/g)) {
    const k = m[1];
    const v = parsed.values[k];
    path = path.replace(`:${k}`, encodeURIComponent(String(v)));
  }

  // body assembly
  let body;
  if (def.method !== "GET" && def.method !== "DELETE") {
    if (parsed.values.body) {
      try { body = JSON.parse(parsed.values.body); }
      catch { errorOut("validation_error", "--body must be valid JSON"); }
    } else {
      body = buildPayload(resourceArg, parsed.values);
    }
  }

  const result = await apiRequest({
    method: def.method,
    path,
    body,
    dryRun: !!global.dry_run,
    verbose: !!global.verbose,
  });

  output(result, !!global.json);
}

main().catch((err) => {
  errorOut("network_error", err.message || String(err));
});
